definition.script:
pipeline {
    agent any
    options {
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '20'))
        timeout(time: 5, unit: 'MINUTES')
    }

    stages {
        stage('Install deps') {
            steps {
                sh '''
                    echo "[frontend-build] npm ci"
                    sleep 1
                    echo "added 873 packages in 4s"
                '''
            }
        }
        stage('Build') {
            steps {
                sh '''
                    set +e
                    echo "[frontend-build] vite build"
                    PICK=$((RANDOM % 5))
                    if [ "$PICK" -eq 0 ]; then
                        echo "npm ERR! code ELIFECYCLE"
                        echo "npm ERR! errno 1"
                        echo "ERROR in src/pages/Dashboard.jsx"
                        echo "Module not found: Cannot resolve 'recharts'"
                        echo "Process exited with status 1"
                        echo "Build FAILED"
                        exit 1
                    fi
                    sleep 2
                    echo "dist/index.html  1.42 kB"
                    echo "dist/assets/index.js  214.55 kB | gzip: 73.21 kB"
                    echo "BUILD SUCCESS"
                '''
            }
        }
    }

    post {
        always {
            script {
                def result    = currentBuild.currentResult ?: 'UNKNOWN'
                def duration  = currentBuild.duration ?: 0
                def payload   = "{\"job_name\":\"${env.JOB_NAME}\",\"build_number\":${env.BUILD_NUMBER},\"status\":\"${result}\",\"duration_ms\":${duration},\"url\":\"${env.BUILD_URL}\"}"
                sh """
                    curl -fsS -X POST \\
                         -H 'Content-Type: application/json' \\
                         -d '${payload}' \\
                         http://backend:8000/api/jenkins/webhook \\
                      || echo 'webhook unreachable'
                """
            }
        }
    }
}
